    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "marketCode": "BTC-USD-SWAP-LIN",
        //         "markPrice": "64276",
        //         "open24h": "63674",
        //         "high24h": "64607",
        //         "low24h": "62933",
        //         "volume24h": "306317655.80000",
        //         "currencyVolume24h": "48.06810",
        //         "openInterest": "72.39250",
        //         "lastTradedPrice": "64300.0",
        //         "lastTradedQuantity": "1.0",
        //         "lastUpdatedAt": "1714925196034"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(ticker, "lastUpdatedAt");
        Object marketId = this.safeString(ticker, "marketCode");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object last = this.safeString(ticker, "lastTradedPrice");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", OxfunCore.this.iso8601(timestamp) );
            put( "high", OxfunCore.this.safeString(ticker, "high24h") );
            put( "low", OxfunCore.this.safeString(ticker, "low24h") );
            put( "bid", null );
            put( "bidVolume", null );
            put( "ask", null );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", OxfunCore.this.safeString(ticker, "open24h") );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", OxfunCore.this.safeString(ticker, "currencyVolume24h") );
            put( "quoteVolume", null );
            put( "markPrice", OxfunCore.this.safeString(ticker, "markPrice") );
            put( "info", ticker );
        }}, market);
    }

    /**
     * @method
     * @name oxfun#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://docs.ox.fun/?json#get-v3-candles
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch (default 24 hours ago)
     * @param {int} [limit] the maximum amount of candles to fetch (default 200, max 500)
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms of the latest candle to fetch (default now)
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            timeframe = this.safeString(this.timeframes, timeframe, timeframe);
            final Object finalTimeframe = timeframe;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "marketCode", Helpers.GetValue(market, "id") );
                put( "timeframe", finalTimeframe );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "startTime", since); // startTime and endTime must be within 7 days of each other
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object until = this.safeInteger(parameters, "until");
            if (Helpers.isTrue(!Helpers.isEqual(until, null)))
            {
                Helpers.addElementToObject(request, "endTime", until);
                parameters = this.omit(parameters, "until");
            } else if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "endTime", this.sum(since, Helpers.multiply(Helpers.multiply(Helpers.multiply(Helpers.multiply(7, 24), 60), 60), 1000))); // for the exchange not to throw an exception if since is younger than 7 days
            }
            Object response = (this.publicGetV3Candles(this.extend(request, parameters))).join();
            //
            //     {
            //         "success": true,
            //         "timeframe": "3600s",
            //         "data": [
            //             {
            //                 "open": "0.03240000",
            //                 "high": "0.03240000",
            //                 "low": "0.03240000",
            //                 "close": "0.03240000",
            //                 "volume": "0",
            //                 "currencyVolume": "0",
            //                 "openedAt": "1714906800000"
            //             },
            //             {
            //                 "open": "0.03240000",
            //                 "high": "0.03240000",
            //                 "low": "0.03240000",
            //                 "close": "0.03240000",
            //                 "volume": "0",
            //                 "currencyVolume": "0",
            //                 "openedAt": "1714903200000"
            //             },
            //             ...
            //         ]
            //     }
            //
            Object result = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(result, market, timeframe, since, limit);
        });

    }

    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        //     {
        //         "open": "0.03240000",
        //         "high": "0.03240000",
        //         "low": "0.03240000",
        //         "close": "0.03240000",
        //         "volume": "0",
        //         "currencyVolume": "0",
        //         "openedAt": "1714906800000"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, "openedAt"), this.safeNumber(ohlcv, "open"), this.safeNumber(ohlcv, "high"), this.safeNumber(ohlcv, "low"), this.safeNumber(ohlcv, "close"), this.safeNumber(ohlcv, "currencyVolume")));
    }

