    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // public fetchTrades
        //
        //     {
        //         "marketCode": "BTC-USD-SWAP-LIN",
        //         "matchPrice": "63900",
        //         "matchQuantity": "1",
        //         "side": "SELL",
        //         "matchType": "TAKER",
        //         "matchedAt": "1714934112352"
        //     }
        //
        //
        // private fetchMyTrades
        //
        //     {
        //         "orderId": "1000104903698",
        //         "clientOrderId": "1715000260094",
        //         "matchId": "400017129522773178",
        //         "marketCode": "ETH-USD-SWAP-LIN",
        //         "side": "BUY",
        //         "matchedQuantity": "0.001",
        //         "matchPrice": "3100.2",
        //         "total": "310.02",
        //         "orderMatchType": "MAKER",
        //         "feeAsset": "OX",
        //         "fee": "0.062004",
        //         "source": "0",
        //         "matchedAt": "1715000267420"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "marketCode");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeInteger(trade, "matchedAt");
        Object fee = new java.util.HashMap<String, Object>() {{
            put( "cost", OxfunCore.this.safeString(trade, "fee") );
            put( "currency", OxfunCore.this.safeCurrencyCode(OxfunCore.this.safeString(trade, "feeAsset")) );
        }};
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", OxfunCore.this.safeString(trade, "matchId") );
            put( "timestamp", timestamp );
            put( "datetime", OxfunCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "type", null );
            put( "order", OxfunCore.this.safeString(trade, "orderId") );
            put( "side", OxfunCore.this.safeStringLower(trade, "side") );
            put( "takerOrMaker", OxfunCore.this.safeStringLower2(trade, "matchType", "orderMatchType") );
            put( "price", OxfunCore.this.safeString(trade, "matchPrice") );
            put( "amount", OxfunCore.this.safeString2(trade, "matchQuantity", "matchedQuantity") );
            put( "cost", null );
            put( "fee", fee );
            put( "info", trade );
        }}, market);
    }

    /**
     * @method
     * @name oxfun#fetchBalance
     * @description query for balance and get the amount of funds available for trading or funds locked in orders
     * @see https://docs.ox.fun/?json#get-v3-balances
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.asset] currency id, if empty the exchange returns info about all currencies
     * @param {string} [params.subAcc] Name of sub account. If no subAcc is given, then the response contains only the account linked to the API-Key.
     * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object response = (this.privateGetV3Balances(parameters)).join();
            //
            //     {
            //         "success": true,
            //         "data": [
            //             {
            //                 "accountId": "106490",
            //                 "name": "main",
            //                 "balances": [
            //                     {
            //                         "asset": "OX",
            //                         "total": "-7.55145065000",
            //                         "available": "-71.16445065000",
            //                         "reserved": "0",
            //                         "lastUpdatedAt": "1715000448946"
            //                     },
            //                     {
            //                         "asset": "ETH",
            //                         "total": "0.01",
            //                         "available": "0.01",
            //                         "reserved": "0",
            //                         "lastUpdatedAt": "1714914512750"
            //                     },
            //                     ...
            //                 ]
            //             },
            //             ...
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object balance = Helpers.GetValue(data, 0);
            Object subAcc = this.safeString(parameters, "subAcc");
            if (Helpers.isTrue(!Helpers.isEqual(subAcc, null)))
            {
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
                {
                    Object b = Helpers.GetValue(data, i);
                    Object name = this.safeString(b, "name");
                    if (Helpers.isTrue(Helpers.isEqual(name, subAcc)))
                    {
                        balance = b;
                        break;
                    }
                }
            }
            return this.parseBalance(balance);
        });

    }

    public Object parseBalance(Object balance)
    {
        //
        //     {
        //         "accountId": "106490",
        //         "name": "main",
        //         "balances": [
        //             {
        //                 "asset": "OX",
        //                 "total": "-7.55145065000",
        //                 "available": "-71.16445065000",
        //                 "reserved": "0",
        //                 "lastUpdatedAt": "1715000448946"
        //             },
        //             {
        //                 "asset": "ETH",
        //                 "total": "0.01",
        //                 "available": "0.01",
        //                 "reserved": "0",
        //                 "lastUpdatedAt": "1714914512750"
        //             },
        //             ...
        //         ]
        //     }
        //
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", balance );
        }};
        Object balances = this.safeList(balance, "balances", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(balances)); i++)
        {
            Object balanceEntry = Helpers.GetValue(balances, i);
            Object currencyId = this.safeString(balanceEntry, "asset");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Helpers.addElementToObject(account, "total", this.safeString(balanceEntry, "total"));
            Helpers.addElementToObject(account, "free", this.safeString(balanceEntry, "available"));
            Helpers.addElementToObject(account, "used", this.safeString(balanceEntry, "reserved"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

