    /**
     * @method
     * @name oxfun#transfer
     * @description transfer currency internally between wallets on the same account
     * @see https://docs.ox.fun/?json#post-v3-transfer
     * @param {string} code unified currency code
     * @param {float} amount amount to transfer
     * @param {string} fromAccount account id to transfer from
     * @param {string} toAccount account id to transfer to
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transfer structure]{@link https://docs.ccxt.com/?id=transfer-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> transfer(Object code, Object amount, Object fromAccount, Object toAccount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // transferring funds between sub-accounts is restricted to API keys linked to the parent account.
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "asset", Helpers.GetValue(currency, "id") );
                put( "quantity", OxfunCore.this.currencyToPrecision(code, amount) );
                put( "fromAccount", fromAccount );
                put( "toAccount", toAccount );
            }};
            Object response = (this.privatePostV3Transfer(this.extend(request, parameters))).join();
            //
            //     {
            //         timestamp: 1715430036267,
            //         datetime: '2024-05-11T12:20:36.267Z',
            //         currency: 'OX',
            //         amount: 10,
            //         fromAccount: '106464',
            //         toAccount: '106570',
            //         info: {
            //         asset: 'OX',
            //         quantity: '10',
            //         fromAccount: '106464',
            //         toAccount: '106570',
            //         transferredAt: '1715430036267'
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            return this.parseTransfer(data, currency);
        });

    }

    /**
     * @method
     * @name oxfun#fetchTransfers
     * @description fetch a history of internal transfers made on an account
     * @see https://docs.ox.fun/?json#get-v3-transfer
     * @param {string} code unified currency code of the currency transferred
     * @param {int} [since] the earliest time in ms to fetch transfers for (default 24 hours ago)
     * @param {int} [limit] the maximum number of transfer structures to retrieve (default 50, max 200)
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] the latest time in ms to fetch transfers for (default time now)
     * @returns {object[]} a list of [transfer structures]{@link https://docs.ccxt.com/?id=transfer-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTransfers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // API keys linked to the parent account can get all account transfers, while API keys linked to a sub-account can only see transfers where the sub-account is either the "fromAccount" or "toAccount"
            Object code = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object currency = null;
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                currency = this.currency(code);
                Helpers.addElementToObject(request, "asset", Helpers.GetValue(currency, "id"));
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "startTime", since); // startTime and endTime must be within 7 days of each other
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object until = this.safeInteger(parameters, "until");
            if (Helpers.isTrue(!Helpers.isEqual(until, null)))
            {
                Helpers.addElementToObject(request, "endTime", until);
                parameters = this.omit(parameters, "until");
            } else if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "endTime", this.sum(since, Helpers.multiply(Helpers.multiply(Helpers.multiply(Helpers.multiply(7, 24), 60), 60), 1000))); // for the exchange not to throw an exception if since is younger than 7 days
            }
            Object response = (this.privateGetV3Transfer(this.extend(request, parameters))).join();
            //
            //     {
            //         "success": true,
            //         "data": [
            //             {
            //                 "asset": "USDT",
            //                 "quantity": "5",
            //                 "fromAccount": "106490",
            //                 "toAccount": "106526",
            //                 "id": "966706320886267905",
            //                 "status": "COMPLETED",
            //                 "transferredAt": "1715085756708"
            //             },
            //             ...
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseTransfers(data, currency, since, limit);
        });

    }

    public Object parseTransfer(Object transfer, Object... optionalArgs)
    {
        //
        // fetchTransfers
        //
        //     {
        //         "asset": "USDT",
        //         "quantity": "5",
        //         "fromAccount": "106490",
        //         "toAccount": "106526",
        //         "id": "966706320886267905",
        //         "status": "COMPLETED",
        //         "transferredAt": "1715085756708"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(transfer, "transferredAt");
        Object currencyId = this.safeString(transfer, "asset");
        return new java.util.HashMap<String, Object>() {{
            put( "id", OxfunCore.this.safeString(transfer, "id") );
            put( "timestamp", timestamp );
            put( "datetime", OxfunCore.this.iso8601(timestamp) );
            put( "currency", OxfunCore.this.safeCurrencyCode(currencyId, currency) );
            put( "amount", OxfunCore.this.safeNumber(transfer, "quantity") );
            put( "fromAccount", OxfunCore.this.safeString(transfer, "fromAccount") );
            put( "toAccount", OxfunCore.this.safeString(transfer, "toAccount") );
            put( "status", OxfunCore.this.parseTransferStatus(OxfunCore.this.safeString(transfer, "status")) );
            put( "info", transfer );
        }};
    }

    public Object parseTransferStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "COMPLETED", "ok" );
        }};
        return this.safeString(statuses, status, status);
    }

    /**
     * @method
     * @name oxfun#fetchDepositAddress
     * @description fetch the deposit address for a currency associated with this account
     * @see https://docs.ox.fun/?json#get-v3-deposit-addresses
     * @param {string} code unified currency code
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.network] network for fetch deposit address
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object networkCode = this.safeString(parameters, "network");
            Object networkId = this.networkCodeToId(networkCode, code);
            if (Helpers.isTrue(Helpers.isEqual(networkId, null)))
            {
                throw new BadRequest((String)Helpers.add(this.id, " fetchDepositAddress() require network parameter")) ;
            }
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            final Object finalNetworkId = networkId;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "asset", Helpers.GetValue(currency, "id") );
                put( "network", finalNetworkId );
            }};
            parameters = this.omit(parameters, "network");
            Object response = (this.privateGetV3DepositAddresses(this.extend(request, parameters))).join();
            //
            //     {"success":true,"data":{"address":"0x998dEc76151FB723963Bd8AFD517687b38D33dE8"}}
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            return this.parseDepositAddress(data, currency);
        });

    }

    public Object parseDepositAddress(Object depositAddress, Object... optionalArgs)
    {
        //
        //     {"address":"0x998dEc76151FB723963Bd8AFD517687b38D33dE8"}
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object address = this.safeString(depositAddress, "address");
        this.checkAddress(address);
        return new java.util.HashMap<String, Object>() {{
            put( "info", depositAddress );
            put( "currency", Helpers.GetValue(currency, "code") );
            put( "network", null );
            put( "address", address );
            put( "tag", null );
        }};
    }

