    public Object parseTransactions(Object transactions, Object... optionalArgs)
    {
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object since = Helpers.getArg(optionalArgs, 1, null);
        Object limit = Helpers.getArg(optionalArgs, 2, null);
        Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
        Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(transactions)); i++)
        {
            Helpers.addElementToObject(transactions, i, this.extend(Helpers.GetValue(transactions, i), parameters));
            Object transaction = this.parseTransaction(Helpers.GetValue(transactions, i), currency);
            ((java.util.List<Object>)result).add(transaction);
        }
        result = this.sortBy(result, "timestamp");
        Object code = ((Helpers.isTrue((!Helpers.isEqual(currency, null))))) ? Helpers.GetValue(currency, "code") : null;
        return this.filterByCurrencySinceLimit(result, code, since, limit);
    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        //  fetchDeposits
        //     {
        //         "asset":"USDC",
        //         "network":"Ethereum",
        //         "address": "0x998dEc76151FB723963Bd8AFD517687b38D33dE8",
        //         "quantity":"50",
        //         "id":"5914",
        //         "status": "COMPLETED",
        //         "txId":"0xf5e79663830a0c6f94d46638dcfbc134566c12facf1832396f81ecb55d3c75dc",
        //         "creditedAt":"1714821645154"
        //     }
        //
        // fetchWithdrawals
        //     {
        //         id: '968163212989431811',
        //         asset: 'OX',
        //         network: 'Arbitrum',
        //         address: '0x90fc1fB49a4ED8f485dd02A2a1Cf576897f6Bfc9',
        //         quantity: '11.7444',
        //         fee: '1.744400000',
        //         status: 'COMPLETED',
        //         txId: '0xe96b2d128b737fdbca927edf355cff42202e65b0fb960e64ffb9bd68c121f69f',
        //         requestedAt: '1715530365450',
        //         completedAt: '1715530527000'
        //     }
        //
        // withdraw
        //     {
        //         "id": "968364664449302529",
        //         "asset": "OX",
        //         "network": "Arbitrum",
        //         "address": "0x90fc1fB49a4ED8f485dd02A2a1Cf576897f6Bfc9",
        //         "quantity": "10",
        //         "externalFee": false,
        //         "fee": "1.6728",
        //         "status": "PENDING",
        //         "requestedAt": "1715591843616"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(transaction, "id");
        Object type = this.safeString(transaction, "type");
        transaction = this.omit(transaction, "type");
        Object address = null;
        Object addressTo = null;
        Object status = null;
        if (Helpers.isTrue(Helpers.isEqual(type, "deposit")))
        {
            address = this.safeString(transaction, "address");
            status = this.parseDepositStatus(this.safeString(transaction, "status"));
        } else if (Helpers.isTrue(Helpers.isEqual(type, "withdrawal")))
        {
            addressTo = this.safeString(transaction, "address");
            status = this.parseWithdrawalStatus(this.safeString(transaction, "status"));
        }
        Object txid = this.safeString(transaction, "txId");
        Object currencyId = this.safeString(transaction, "asset");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object network = this.safeString(transaction, "network");
        Object networkCode = this.networkIdToCode(network);
        Object timestamp = this.safeInteger2(transaction, "creditedAt", "requestedAt");
        Object amount = this.safeNumber(transaction, "quantity");
        Object feeCost = this.safeNumber(transaction, "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", code );
            }};
        }
        final Object finalTransaction = transaction;
        final Object finalAddress = address;
        final Object finalAddressTo = addressTo;
        final Object finalType = type;
        final Object finalStatus = status;
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", finalTransaction );
            put( "id", id );
            put( "txid", txid );
            put( "timestamp", timestamp );
            put( "datetime", OxfunCore.this.iso8601(timestamp) );
            put( "network", networkCode );
            put( "address", finalAddress );
            put( "addressTo", finalAddressTo );
            put( "addressFrom", null );
            put( "tag", null );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", finalType );
            put( "amount", amount );
            put( "currency", code );
            put( "status", finalStatus );
            put( "updated", null );
            put( "internal", null );
            put( "comment", null );
            put( "fee", finalFee );
        }};
    }

    public Object parseDepositStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "COMPLETED", "ok" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseWithdrawalStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "COMPLETED", "ok" );
            put( "PROCESSING", "pending" );
            put( "IN SWEEPING", "pending" );
            put( "PENDING", "pending" );
            put( "ON HOLD", "pending" );
            put( "CANCELED", "canceled" );
            put( "FAILED", "failed" );
        }};
        return this.safeString(statuses, status, status);
    }

    /**
     * @method
     * @name oxfun#withdraw
     * @description make a withdrawal
     * @see https://docs.ox.fun/?json#post-v3-withdrawal
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.network] network for withdraw
     * @param {bool} [params.externalFee] if false, then the fee is taken from the quantity, also with the burn fee for asset SOLO
     *
     * EXCHANGE SPECIFIC PARAMETERS
     * @param {string} [params.tfaType] GOOGLE, or AUTHY_SECRET, or YUBIKEY, for 2FA
     * @param {string} [params.code] 2FA code
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            var tagparametersVariable = this.handleWithdrawTagAndParams(tag, parameters);
            tag = ((java.util.List<Object>) tagparametersVariable).get(0);
            parameters = ((java.util.List<Object>) tagparametersVariable).get(1);
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object stringAmount = this.currencyToPrecision(code, amount);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "asset", Helpers.GetValue(currency, "id") );
                put( "address", address );
                put( "quantity", stringAmount );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(tag, null)))
            {
                Helpers.addElementToObject(request, "memo", tag);
            }
            Object networkCode = null;
            var networkCodeparametersVariable = this.handleNetworkCodeAndParams(parameters);
            networkCode = ((java.util.List<Object>) networkCodeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) networkCodeparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(networkCode, null)))
            {
                Helpers.addElementToObject(request, "network", this.networkCodeToId(networkCode));
            }
            Helpers.addElementToObject(request, "externalFee", false);
            Object response = (this.privatePostV3Withdrawal(this.extend(request, parameters))).join();
            //
            //     {
            //         "success": true,
            //         "data": {
            //             "id": "968364664449302529",
            //             "asset": "OX",
            //             "network": "Arbitrum",
            //             "address": "0x90fc1fB49a4ED8f485dd02A2a1Cf576897f6Bfc9",
            //             "quantity": "10",
            //             "externalFee": false,
            //             "fee": "1.6728",
            //             "status": "PENDING",
            //             "requestedAt": "1715591843616"
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Helpers.addElementToObject(data, "type", "withdrawal");
            return this.parseTransaction(data, currency);
        });

    }

    /**
     * @method
     * @name oxfun#fetchPositions
     * @description fetch all open positions
     * @see https://docs.ox.fun/?json#get-v3-positions
     * @param {string[]|undefined} symbols list of unified market symbols
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.subAcc]
     * @returns {object[]} a list of [position structure]{@link https://docs.ccxt.com/?id=position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchPositions(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // Calling this endpoint using an API key pair linked to the parent account with the parameter "subAcc"
            // allows the caller to include positions of additional sub-accounts in the response.
            // This feature does not work when using API key pairs linked to a sub-account
            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            symbols = this.marketSymbols(symbols);
            Object response = (this.privateGetV3Positions(parameters)).join();
            //
            //     {
            //         "success": true,
            //         "data": [
            //             {
            //                 "accountId": "106490",
            //                 "name": "main",
            //                 "positions": [
            //                     {
            //                         "marketCode": "BTC-USD-SWAP-LIN",
            //                         "baseAsset": "BTC",
            //                         "counterAsset": "USD",
            //                         "position": "0.00010",
            //                         "entryPrice": "64300.0",
            //                         "markPrice": "63278",
            //                         "positionPnl": "-10.1900",
            //                         "estLiquidationPrice": "0",
            //                         "lastUpdatedAt": "1714915841448"
            //                     },
            //                     ...
            //                 ]
            //             },
            //             {
            //                 "accountId": "106526",
            //                 "name": "testSubAccount",
            //                 "positions": [
            //                     {
            //                         "marketCode": "ETH-USD-SWAP-LIN",
            //                         "baseAsset": "ETH",
            //                         "counterAsset": "USD",
            //                         "position": "0.001",
            //                         "entryPrice": "3080.5",
            //                         "markPrice": "3062.0",
            //                         "positionPnl": "-1.8500",
            //                         "estLiquidationPrice": "0",
            //                         "lastUpdatedAt": "1715089678013"
            //                     },
            //                     ...
            //                 ]
            //             }
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object allPositions = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object account = Helpers.GetValue(data, i);
                Object positions = this.safeList(account, "positions", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                allPositions = this.arrayConcat(allPositions, positions);
            }
            return this.parsePositions(allPositions, symbols);
        });

    }

