    /**
     * @method
     * @name oxfun#createOrder
     * @description create a trade order
     * @see https://docs.ox.fun/?json#post-v3-orders-place
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market', 'limit', 'STOP_LIMIT' or 'STOP_MARKET'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.clientOrderId] a unique id for the order
     * @param {int} [params.timestamp] in milliseconds. If an order reaches the matching engine and the current timestamp exceeds timestamp + recvWindow, then the order will be rejected.
     * @param {int} [params.recvWindow] in milliseconds. If an order reaches the matching engine and the current timestamp exceeds timestamp + recvWindow, then the order will be rejected. If timestamp is provided without recvWindow, then a default recvWindow of 1000ms is used.
     * @param {string} [params.responseType] FULL or ACK
     * @param {float} [params.cost] the quote quantity that can be used as an alternative for the amount for market buy orders
     * @param {float} [params.triggerPrice] The price at which a trigger order is triggered at
     * @param {float} [params.limitPrice] Limit price for the STOP_LIMIT order
     * @param {bool} [params.postOnly] if true, the order will only be posted if it will be a maker order
     * @param {string} [params.timeInForce] GTC (default), IOC, FOK, PO, MAKER_ONLY or MAKER_ONLY_REPRICE (reprices order to the best maker only price if the specified price were to lead to a taker trade)
     * @param {string} [params.selfTradePrevention] NONE, EXPIRE_MAKER, EXPIRE_TAKER or EXPIRE_BOTH for more info check here {@link https://docs.ox.fun/?json#self-trade-prevention-modes}
     * @param {string} [params.displayQuantity] for an iceberg order, pass both quantity and displayQuantity fields in the order request
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object responseType = this.safeString(parameters, "responseType", "FULL");
            Object timestamp = this.safeInteger(parameters, "timestamp", this.milliseconds());
            Object request = new java.util.HashMap<String, Object>() {{
                put( "responseType", responseType );
                put( "timestamp", timestamp );
            }};
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("responseType", "timestamp")));
            Object recvWindow = this.safeInteger(parameters, "recvWindow");
            if (Helpers.isTrue(!Helpers.isEqual(recvWindow, null)))
            {
                Helpers.addElementToObject(request, "recvWindow", recvWindow);
                parameters = this.omit(parameters, "recvWindow");
            }
            Object orderRequest = this.createOrderRequest(symbol, type, side, amount, price, parameters);
            Helpers.addElementToObject(request, "orders", new java.util.ArrayList<Object>(java.util.Arrays.asList(orderRequest)));
            Object response = (this.privatePostV3OrdersPlace(request)).join();
            //
            // accepted market order responseType FULL
            //     {
            //         "success": true,
            //         "data": [
            //             {
            //                 "notice": "OrderMatched",
            //                 "accountId": "106490",
            //                 "orderId": "1000109901865",
            //                 "submitted": true,
            //                 "clientOrderId": "0",
            //                 "marketCode": "OX-USDT",
            //                 "status": "FILLED",
            //                 "side": "SELL",
            //                 "isTriggered": false,
            //                 "quantity": "150.0",
            //                 "amount": "0.0",
            //                 "remainQuantity": "0.0",
            //                 "matchId": "100017047880451399",
            //                 "matchPrice": "0.01465",
            //                 "matchQuantity": "150.0",
            //                 "feeInstrumentId": "USDT",
            //                 "fees": "0.0015382500",
            //                 "orderType": "MARKET",
            //                 "createdAt": "1715592472236",
            //                 "lastMatchedAt": "1715592472200",
            //                 "displayQuantity": "150.0"
            //             }
            //         ]
            //     }
            //
            // accepted limit order responseType FULL
            //     {
            //         "success": true,
            //         "data": [
            //             {
            //                 "notice": "OrderOpened",
            //                 "accountId": "106490",
            //                 "orderId": "1000111482406",
            //                 "submitted": true,
            //                 "clientOrderId": "0",
            //                 "marketCode": "ETH-USD-SWAP-LIN",
            //                 "status": "OPEN",
            //                 "side": "SELL",
            //                 "price": "4000.0",
            //                 "isTriggered": false,
            //                 "quantity": "0.01",
            //                 "amount": "0.0",
            //                 "orderType": "LIMIT",
            //                 "timeInForce": "GTC",
            //                 "createdAt": "1715763507682",
            //                 "displayQuantity": "0.01"
            //             }
            //         ]
            //     }
            //
            // accepted order responseType ACK
            //     {
            //         "success": true,
            //         "data": [
            //             {
            //                 "accountId": "106490",
            //                 "orderId": "1000109892193",
            //                 "submitted": true,
            //                 "marketCode": "OX-USDT",
            //                 "side": "BUY",
            //                 "price": "0.01961",
            //                 "isTriggered": false,
            //                 "quantity": "100",
            //                 "orderType": "MARKET",
            //                 "timeInForce": "IOC",
            //                 "createdAt": "1715591529057",
            //                 "selfTradePreventionMode": "NONE"
            //             }
            //         ]
            //     }
            //
            //  rejected order (balance insufficient)
            //     {
            //         "success": true,
            //         "data": [
            //             {
            //                 "code": "710001",
            //                 "message": "System failure, exception thrown -> null",
            //                 "submitted": false,
            //                 "marketCode": "OX-USDT",
            //                 "side": "BUY",
            //                 "price": "0.01961",
            //                 "amount": "100",
            //                 "orderType": "MARKET",
            //                 "timeInForce": "IOC",
            //                 "createdAt": "1715591678835",
            //                 "source": 11,
            //                 "selfTradePreventionMode": "NONE"
            //             }
            //         ]
            //     }
            //
            // rejected order (bad request)
            //     {
            //         "success": true,
            //         "data": [
            //             {
            //                 "code": "20044",
            //                 "message": "Amount is not supported for this order type",
            //                 "submitted": false,
            //                 "marketCode": "OX-USDT",
            //                 "side": "SELL",
            //                 "amount": "200",
            //                 "orderType": "MARKET",
            //                 "createdAt": "1715592079986",
            //                 "source": 11
            //             }
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object order = this.safeDict(data, 0, new java.util.HashMap<String, Object>() {{}});
            return this.parseOrder(order);
        });

    }

    /**
     * @method
     * @name oxfun#createOrders
     * @description create a list of trade orders
     * @see https://docs.ox.fun/?json#post-v3-orders-place
     * @param {Array} orders list of orders to create, each object should contain the parameters required by createOrder, namely symbol, type, side, amount, price and params
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.timestamp] *for all orders* in milliseconds. If orders reach the matching engine and the current timestamp exceeds timestamp + recvWindow, then all orders will be rejected.
     * @param {int} [params.recvWindow] *for all orders* in milliseconds. If orders reach the matching engine and the current timestamp exceeds timestamp + recvWindow, then all orders will be rejected. If timestamp is provided without recvWindow, then a default recvWindow of 1000ms is used.
     * @param {string} [params.responseType] *for all orders* FULL or ACK
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrders(Object orders, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object ordersRequests = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(orders)); i++)
            {
                Object rawOrder = Helpers.GetValue(orders, i);
                Object symbol = this.safeString(rawOrder, "symbol");
                Object type = this.safeString(rawOrder, "type");
                Object side = this.safeString(rawOrder, "side");
                Object amount = this.safeNumber(rawOrder, "amount");
                Object price = this.safeNumber(rawOrder, "price");
                Object orderParams = this.safeDict(rawOrder, "params", new java.util.HashMap<String, Object>() {{}});
                Object orderRequest = this.createOrderRequest(symbol, type, side, amount, price, orderParams);
                ((java.util.List<Object>)ordersRequests).add(orderRequest);
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "responseType", "FULL" );
                put( "timestamp", OxfunCore.this.milliseconds() );
                put( "orders", ordersRequests );
            }};
            Object response = (this.privatePostV3OrdersPlace(this.extend(request, parameters))).join();
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOrders(data);
        });

    }

    public Object createOrderRequest(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {
        /**
        * @param {string} symbol unified symbol of the market to create an order in
        * @param {string} type 'market', 'limit', 'STOP_LIMIT' or 'STOP_MARKET'
        * @param {string} side 'buy' or 'sell'
        * @param {float} amount how much of currency you want to trade in units of base currency
        * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
        * @param {object} [params] extra parameters specific to the exchange API endpoint
        * @param {int} [params.clientOrderId] a unique id for the order
        * @param {float} [params.cost] the quote quantity that can be used as an alternative for the amount for market buy orders
        * @param {float} [params.triggerPrice] The price at which a trigger order is triggered at
        * @param {float} [params.limitPrice] Limit price for the STOP_LIMIT order
        * @param {bool} [params.postOnly] if true, the order will only be posted if it will be a maker order
        * @param {string} [params.timeInForce] GTC (default), IOC, FOK, PO, MAKER_ONLY or MAKER_ONLY_REPRICE (reprices order to the best maker only price if the specified price were to lead to a taker trade)
        * @param {string} [params.selfTradePrevention] NONE, EXPIRE_MAKER, EXPIRE_TAKER or EXPIRE_BOTH for more info check here {@link https://docs.ox.fun/?json#self-trade-prevention-modes}
        * @param {string} [params.displayQuantity] for an iceberg order, pass both quantity and displayQuantity fields in the order request
        */
        Object price = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object market = this.market(symbol);
        Object request = new java.util.HashMap<String, Object>() {{
            put( "marketCode", Helpers.GetValue(market, "id") );
            put( "side", ((String)side).toUpperCase() );
            put( "source", 1000 );
        }};
        Object cost = this.safeString2(parameters, "cost", "amount");
        if (Helpers.isTrue(!Helpers.isEqual(cost, null)))
        {
            Helpers.addElementToObject(request, "amount", cost); // todo costToPrecision
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("cost", "amount")));
        } else
        {
            Helpers.addElementToObject(request, "quantity", amount); // todo amountToPrecision
        }
        Object triggerPrice = this.safeString2(parameters, "triggerPrice", "stopPrice");
        Object orderType = ((String)type).toUpperCase();
        if (Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(orderType, "MARKET")))
            {
                orderType = "STOP_MARKET";
            } else if (Helpers.isTrue(Helpers.isEqual(orderType, "LIMIT")))
            {
                orderType = "STOP_LIMIT";
            }
            Helpers.addElementToObject(request, "stopPrice", triggerPrice); // todo priceToPrecision
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("triggerPrice", "stopPrice")));
        }
        Helpers.addElementToObject(request, "orderType", orderType);
        if (Helpers.isTrue(Helpers.isEqual(orderType, "STOP_LIMIT")))
        {
            Helpers.addElementToObject(request, "limitPrice", price); // todo priceToPrecision
        } else if (Helpers.isTrue(!Helpers.isEqual(price, null)))
        {
            Helpers.addElementToObject(request, "price", price); // todo priceToPrecision
        }
        Object postOnly = null;
        Object isMarketOrder = Helpers.isTrue((Helpers.isEqual(orderType, "MARKET"))) || Helpers.isTrue((Helpers.isEqual(orderType, "STOP_MARKET")));
        var postOnlyparametersVariable = this.handlePostOnly(isMarketOrder, false, parameters);
        postOnly = ((java.util.List<Object>) postOnlyparametersVariable).get(0);
        parameters = ((java.util.List<Object>) postOnlyparametersVariable).get(1);
        Object timeInForce = this.safeStringUpper(parameters, "timeInForce");
        if (Helpers.isTrue(Helpers.isTrue(postOnly) && Helpers.isTrue((!Helpers.isEqual(timeInForce, "MAKER_ONLY_REPRICE")))))
        {
            Helpers.addElementToObject(request, "timeInForce", "MAKER_ONLY");
        }
        Object selfTradePrevention = null;
        var selfTradePreventionparametersVariable = this.handleOptionAndParams(parameters, "createOrder", "selfTradePrevention");
        selfTradePrevention = ((java.util.List<Object>) selfTradePreventionparametersVariable).get(0);
        parameters = ((java.util.List<Object>) selfTradePreventionparametersVariable).get(1);
        if (Helpers.isTrue(!Helpers.isEqual(selfTradePrevention, null)))
        {
            Helpers.addElementToObject(request, "selfTradePreventionMode", ((String)selfTradePrevention).toUpperCase());
        }
        return this.extend(request, parameters);
    }

    /**
     * @method
     * @name oxfun#createMarketBuyOrderWithCost
     * @description create a market buy order by providing the symbol and cost
     * @see https://open.big.one/docs/spot_orders.html#create-order
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {float} cost how much you want to trade in units of the quote currency
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createMarketBuyOrderWithCost(Object symbol, Object cost, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            if (!Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                throw new NotSupported((String)Helpers.add(this.id, " createMarketBuyOrderWithCost() supports spot orders only")) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "cost", cost );
            }};
            return (this.createOrder(symbol, "market", "buy", null, null, this.extend(request, parameters))).join();
        });

    }

